        public IActionResult Index(string arama, string sirala)
        {
            var sorgu = Hayvanlar.AsQueryable();

            if (!string.IsNullOrWhiteSpace(arama))
            {
                string kelime = arama.Trim().ToLower();
                sorgu = sorgu.Where(h => h.Ad.ToLower().Contains(kelime) ||
                                         h.Tur.ToLower().Contains(kelime) ||
                                         h.Ulke.ToLower().Contains(kelime));
            }

            sorgu = sirala switch
            {
                "tur" => sorgu.OrderBy(h => h.Tur),
                "ulke" => sorgu.OrderBy(h => h.Ulke),
                "omur" => sorgu.OrderBy(h => h.Omur),
                "boy" => sorgu.OrderBy(h => h.Boy),
                "agirlik" => sorgu.OrderBy(h => h.Agirlik),
                _ => sorgu.OrderBy(h => h.Ad)
            };

            return View(sorgu.ToList());
        }

        public IActionResult Giris()
        {
            return View();
        }

        public IActionResult detaylar(int id)
        {
            var hayvan = Hayvanlar.FirstOrDefault(x => x.Id == id);

            if (hayvan == null)
            {
                return RedirectToAction("Index");
            }

            return View(hayvan);
        }

        public IActionResult Sil(int id)
        {
            var hayvan = Hayvanlar.FirstOrDefault(x => x.Id == id);
            if (hayvan != null)
            {
                Hayvanlar.Remove(hayvan);
            }
            return RedirectToAction("Index");
        }
    }
}